import {
  ellipse, polygon, rectangle, circle,
  union, dilate, render,
} from '../../src/index.js';

// Top-down silhouette of a stealth jet (F-22-ish) — bilaterally symmetric.

// --- Fuselage (centerline) ---
const fuselage = ellipse(0.45, 0.06, [0, 0]);
const nose     = polygon([[ 0.45, 0.00], [0.58, 0.015], [0.58, -0.015]]);
const cockpit  = ellipse(0.08, 0.035, [0.20, 0.00]);
const exhaust  = rectangle([0.10, 0.10], [-0.45, 0.00]);

// --- Wings (bilateral pair) ---
// LEFT (positive y in 2D top-down)
const wingL = polygon([
  [-0.10, 0.05], [ 0.18, 0.05], [ 0.00, 0.36], [-0.28, 0.28],
]);
// RIGHT (negative y) — mirror of left
const wingR = polygon([
  [-0.10,-0.05], [ 0.18,-0.05], [ 0.00,-0.36], [-0.28,-0.28],
]);

// --- Tail fins (bilateral pair) ---
const tailL = polygon([
  [-0.32, 0.05], [-0.34, 0.18], [-0.42, 0.16], [-0.42, 0.05],
]);
const tailR = polygon([
  [-0.32,-0.05], [-0.34,-0.18], [-0.42,-0.16], [-0.42,-0.05],
]);

// --- Horizontal stabilizers (bilateral) ---
const hstabL = polygon([
  [-0.38, 0.05], [-0.30, 0.06], [-0.34, 0.20], [-0.44, 0.18],
]);
const hstabR = polygon([
  [-0.38,-0.05], [-0.30,-0.06], [-0.34,-0.20], [-0.44,-0.18],
]);

const jet = union(fuselage, nose, cockpit, exhaust,
                  wingL, wingR, tailL, tailR, hstabL, hstabR);

const sky = rectangle([1.6, 1.2], [0, 0.0]);

const layers = [
  { sdf: sky,                     color: [110, 140, 175] },
  { sdf: dilate(jet, 0.012),      color: [30, 35, 45]    },
  { sdf: jet,                     color: [75, 82, 95]    },
  { sdf: cockpit,                 color: [40, 55, 80]    },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [120, 150, 185], bottom: [180, 200, 225] },
});
```

**Composition notes**: Top-down view of a stealth jet. Wings/tail-fins/horizontal-stabilizers are emitted as **bilateral pairs** (L+R), one on each side of the y=0 centerline. Fuselage / nose / cockpit / exhaust sit ON the centerline (no mirror). Author wants the wings to flap in counter-phase — left up while right down — like a bird-of-prey idle pose.
